INSERT INTO news (slug, date_label, tag, title, text, content, image, published, images)
VALUES (
  'price-na-semena-optom-2026-kak-formiruetsya-cena',
  '27 апреля 2026',
  'Прайс 2026',
  'Прайс на семена оптом 2026 — как формируется цена и от чего зависит скидка',
  'Объясняем, как складывается оптовая цена на семена, какие факторы дают скидку и как магазину получить лучшие условия на сезон 2026.',
  'Многие розничные магазины и фермеры спрашивают: «Почему прайс на семена оптом у разных поставщиков отличается на 20–30%, хотя сорта одинаковые?» Разбираем по полочкам, как реально формируется оптовая цена и за счёт чего можно получить дополнительную скидку.\n\nИз чего складывается оптовая цена семян:\n— Прямой контракт с селекционной станцией. Когда поставщик закупает семена напрямую у производителя, без промежуточных дистрибьюторов, цена ниже на 15–25%. Мы работаем именно по такой схеме.\n— Объём партии. Чем больше единовременный заказ, тем меньше доля логистики и фасовки в каждой пачке.\n— Сорт и репродукция. Элитные семена и гибриды F1 объективно дороже массовых сортов — это нормально и связано со стоимостью семеноводства.\n— Сезонность закупки. Заказы, сделанные до начала весеннего ажиотажа (январь-февраль), получают самые лучшие цены.\n\nОт чего зависит размер скидки:\n— Сумма заказа: чем больше чек, тем выше процент скидки.\n— Регулярность сотрудничества. Постоянным клиентам мы держим фиксированные оптовые цены весь сезон.\n— Готовность забрать со склада в Иваново — это экономит логистику и тоже отражается на скидке.\n— Предоплата по заказу — стандартный фактор, который снижает цену для клиента.\n\nКак получить актуальный прайс на семена оптом 2026: позвоните по телефону или оставьте заявку на сайте — менеджер пришлёт прайс-лист по WhatsApp или на электронную почту. Прайс обновляется регулярно, в нём указаны все 560+ позиций ассортимента.\n\nДля наших клиентов из Иваново и Ивановской области действует доставка по городу и области. Семена напрямую от селекционных станций, всхожесть 97%, индивидуальные условия для розничных магазинов.',
  'https://cdn.poehali.dev/projects/6e30ca34-8fe1-4535-8d16-622fe38c58fb/files/9235f268-44b6-48fb-a5a4-d5d5a0e5a1f7.jpg',
  TRUE,
  '[]'::jsonb
);

INSERT INTO news (slug, date_label, tag, title, text, content, image, published, images)
VALUES (
  'semena-ogurcov-optom-top-10-sortov-dlya-ivanovskoy-oblasti',
  '28 апреля 2026',
  'Сорта',
  'Семена огурцов оптом: ТОП-10 сортов для Ивановской области',
  'Подборка проверенных сортов и гибридов огурцов, которые лучше всего показывают себя в условиях средней полосы и хорошо продаются в розничных магазинах.',
  'Огурцы — одна из самых ходовых позиций в любом весеннем ассортименте семян. Чтобы помочь розничным магазинам и садоводам с выбором, мы собрали ТОП-10 сортов и гибридов, которые стабильно показывают высокую урожайность в Ивановской области.\n\nДля теплиц (партенокарпические гибриды F1):\n— «Герман» — ультраранний, плодоносит длинными волнами, очень популярен в рознице.\n— «Зятёк» — пучковый гибрид, не требует опыления, прощает огрехи в уходе.\n— «Мурашка» — корнишонный тип, идеален для засолки и заготовок.\n— «Маша» — устойчив к основным болезням, плоды без горечи.\n\nДля открытого грунта (пчёлоопыляемые и универсальные):\n— «Конкурент» — классика, проверенная десятилетиями, стабильная всхожесть.\n— «Феникс» — поздний сорт, плодоносит до заморозков.\n— «Нежинский» — лучший выбор для засолки, плотная хрустящая мякоть.\n\nДля любителей экзотики и премиум-полки:\n— «Китайский змей» — длинноплодный, гладкий, хорошо идёт в свежем виде.\n— «Кураж F1» — пучковый, обильное плодоношение, для опытных огородников.\n— «Парижский корнишон» — мелкоплодный, востребован для заготовок.\n\nПочему эти сорта работают в Иваново:\nИвановская область — зона рискованного земледелия с коротким летом и переменчивой погодой. Сорта из подборки выбраны с учётом устойчивости к перепадам температур, типичным болезням и поздним заморозкам. Все семена огурцов оптом мы получаем напрямую от селекционных станций — это гарантия сортовой чистоты и всхожести 97%.\n\nЕсли у вас магазин в Иваново, Кохме, Шуе или Кинешме — оформите заявку на оптовую партию, мы сформируем оптимальный набор под ваш регион и доставим семена по городу Иваново и области.',
  'https://cdn.poehali.dev/projects/6e30ca34-8fe1-4535-8d16-622fe38c58fb/files/37376634-408a-4556-9c2e-f6875f56ebc6.jpg',
  TRUE,
  '[]'::jsonb
);

INSERT INTO news (slug, date_label, tag, title, text, content, image, published, images)
VALUES (
  'semena-tomatov-optom-kakie-sorta-berut-magaziny-i-fermery',
  '29 апреля 2026',
  'Сорта',
  'Семена томатов оптом: какие сорта берут магазины и фермеры',
  'Рассказываем, какие сорта и гибриды томатов чаще всего заказывают оптом в сезоне 2026 — отдельно для розничных магазинов и для фермерских хозяйств.',
  'Томаты — вторая по объёмам позиция в оптовых заказах семян после огурцов. По нашей статистике за последние сезоны, спрос розничных магазинов и крупных фермеров заметно отличается. Разбираем, какие сорта томатов оптом стабильно берут разные категории клиентов.\n\nЧто заказывают розничные магазины:\nМагазины ориентируются на массовый спрос частных садоводов. Здесь хорошо идут универсальные сорта с понятным названием и узнаваемой упаковкой:\n— «Бычье сердце» — крупноплодный, классика для салата.\n— «Дамские пальчики» — удлинённый, для засолки и консервации.\n— «Чёрный принц» — экзотическая окраска, премиальная полка.\n— «Шоколадка F1», «Чёрри Блосэм F1» — мелкоплодные для свежего стола.\n— «Розовый гигант» — крупноплодный розовоплодный, очень популярен у дачников.\n\nЧто берут фермеры и тепличные хозяйства:\nЗдесь приоритет — урожайность, лёжкость, устойчивость к болезням и единообразие плодов:\n— «Бенито F1» — детерминантный, для открытого грунта, плотные плоды для перевозки.\n— «Бобкат F1» — крупноплодный, устойчив к жаре.\n— «Президент II F1» — высокая урожайность, идёт под заводскую переработку.\n— «Полбиг F1» — ультраранний, первая волна томатов на рынке.\n— «Семко-Синдбад F1» — стабильный гибрид для теплиц.\n\nКак выбрать сорта для своей точки продаж:\nЕсли ваш магазин работает с дачниками — делайте упор на узнаваемые «бабушкины» сорта плюс 2–3 модных гибрида с яркой окраской. Если основной клиент — фермер или тепличник — берите проверенные F1 в большой фасовке.\n\nВсе семена томатов оптом мы получаем напрямую от селекционных станций. Всхожесть 97%, прайс на семена оптом высылаем по запросу. Для клиентов в Иваново и Ивановской области — доставка по городу и области, для остального региона — самовывоз со склада или удобная отгрузка.',
  'https://cdn.poehali.dev/projects/6e30ca34-8fe1-4535-8d16-622fe38c58fb/files/edd494ff-8360-4cbe-9238-df4393857a49.jpg',
  TRUE,
  '[]'::jsonb
);